#!/usr/bin/env python3
"""Generate guru_brain.json with 1000+ entries from templates."""
import json, sys, io, os, copy
sys.stdout = io.TextIOWrapper(sys.stdout.buffer, encoding='utf-8')

# Load existing data
starter = json.load(open('prompts/guru_brain_starter.json', 'r', encoding='utf-8'))
existing = {p['id']: p for p in starter['problems']}

# Load part1 if exists
p1_path = 'resources/knowledge_base/brain_part1.json'
if os.path.exists(p1_path):
    try:
        p1 = json.load(open(p1_path, 'r', encoding='utf-8'))
        for p in p1.get('problems', []):
            if p['id'] not in existing:
                existing[p['id']] = p
    except: pass

print(f"Starting with {len(existing)} existing entries")

