# Minimum counts per category
MINIMUMS = {
    "windows": 80, "outlook": 60, "teams": 50, "office": 40,
    "drucker": 45, "netzwerk": 60, "performance": 35, "hardware": 40,
    "sicherheit": 40, "sap": 25, "zscaler": 20, "enaio": 15,
    "festplatte": 25, "onedrive": 20, "intune": 20, "browser": 20,
    "sprache": 15, "standard_apps": 15, "zertifikate": 15,
    "wiederherstellung": 15, "barrierefreiheit": 15, "personalisierung": 20,
    "privacy": 15, "remote": 15, "systemeinstellungen": 20,
    "audio_display": 15, "email": 15, "updates": 20, "dienste": 15,
}

# Count existing per category
cat_counts = {}
for pid, p in existing.items():
    cat = p.get('category', '?')
    cat_counts[cat] = cat_counts.get(cat, 0) + 1

# Add template entries
for cat_slug, cat_data in CATEGORIES.items():
    prefix = cat_data['prefix']
    for entry in cat_data['entries']:
        if entry['id'] not in existing:
            existing[entry['id']] = entry
            existing[entry['id']]['category'] = cat_slug
            cat_counts[cat_slug] = cat_counts.get(cat_slug, 0) + 1

print(f"\nAfter adding templates: {len(existing)} entries")
for cat, count in sorted(cat_counts.items()):
    minimum = MINIMUMS.get(cat, 10)
    need = max(0, minimum - count)
    print(f"  {cat}: {count}/{minimum} {'OK' if need == 0 else f'(need {need} more)'}")

