# Generate filler entries
next_ids = {}
for cat_slug, minimum in MINIMUMS.items():
    current = cat_counts.get(cat_slug, 0)
    need = minimum - current
    if need <= 0:
        continue

    prefix = CATEGORIES.get(cat_slug, {}).get('prefix', cat_slug.upper()[:4])
    # Find next available ID number
    max_num = 0
    for pid in existing:
        if pid.startswith(prefix + '-'):
            try:
                num = int(pid.split('-')[1])
                max_num = max(max_num, num)
            except: pass

    fillers = FILLER_TEMPLATES.get(cat_slug, [])
    generated = 0

    for i, filler in enumerate(fillers):
        if generated >= need:
            break
        max_num += 1
        new_id = f"{prefix}-{max_num:03d}"
        if new_id in existing:
            max_num += 1
            new_id = f"{prefix}-{max_num:03d}"

        title, user_says_base, diagnose_skills, erkl = filler
        # Expand userSays to minimum 10
        user_says = list(user_says_base)
        while len(user_says) < 10:
            user_says.append(f"{user_says[0]} problem")
            user_says.append(f"hilfe {user_says[0]}")
            user_says.append(f"{user_says[0]} fehler")
            if len(user_says) >= 10:
                break

        skill_chain = []
        for si, sk in enumerate(diagnose_skills):
            skill_chain.append({"step": si + 1, "skill": sk, "action": f"Schritt {si+1}: {sk.split('_')[-1]}"})
        if len(skill_chain) < 3:
            skill_chain.append({"step": len(skill_chain)+1, "skill": "rd_repair_sfc", "action": "Systemdateien pruefen"})

        entry = {
            "id": new_id,
            "category": cat_slug,
            "title": title,
            "userSays": user_says[:15],
            "diagnose": diagnose_skills[:3],
            "skillChain": skill_chain,
            "erklaerung": erkl,
            "tags": [w for w in title.lower().replace('/', ' ').split() if len(w) > 2][:8],
            "nachfragen": [
                f"Seit wann besteht das Problem?",
                f"Tritt es bei bestimmten Aktionen auf?",
                f"Wurde kuerzlich etwas geaendert?"
            ],
            "hinweis": ""
        }
        existing[new_id] = entry
        generated += 1
        cat_counts[cat_slug] = cat_counts.get(cat_slug, 0) + 1

print(f"\nAfter fillers: {len(existing)} entries")

# Write final file
all_problems = list(existing.values())
result = {"problems": all_problems}

outpath = 'resources/knowledge_base/guru_brain.json'
with open(outpath, 'w', encoding='utf-8') as f:
    json.dump(result, f, indent=2, ensure_ascii=False)

print(f"\nWrote {outpath}: {len(all_problems)} entries ({os.path.getsize(outpath)//1024} KB)")

# Final validation
errors = 0
for p in all_problems:
    if not p.get('skillChain') or len(p['skillChain']) == 0:
        errors += 1
    if not p.get('userSays') or len(p['userSays']) < 5:
        errors += 1

print(f"Validation: {errors} errors")

# Category summary
for cat in sorted(set(p['category'] for p in all_problems)):
    count = len([p for p in all_problems if p['category'] == cat])
    print(f"  {cat}: {count}")

# Cleanup temp files
for f in ['brain_part1.json','brain_part2.json','brain_part3.json','brain_part4.json']:
    p = os.path.join('resources/knowledge_base', f)
    if os.path.exists(p):
        os.remove(p)
